import React from "react";
import { motion } from "framer-motion";

const highlights = [
  {
    number: "01",
    title: "AI & Machine Learning",
    description:
      "Building intelligent systems using machine learning, deep learning, and modern AI architectures.",
  },
  {
    number: "02",
    title: "Agentic AI & GenAI",
    description:
      "Designing LangGraph multi-agent workflows, RAG systems, and LLM-powered applications.",
  },
  {
    number: "03",
    title: "Financial Intelligence",
    description:
      "Developing AML detection engines, fraud intelligence platforms, and AI-driven risk analysis systems.",
  },
];

export default function About() {
  return (
    <section
      id="about"
      className="py-40 px-6 bg-[#050505]"
    >
      <div className="max-w-7xl mx-auto">
        {/* Section Header */}
        <motion.div
          initial={{ opacity: 0, y: 30 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true }}
          className="mb-24"
        >
          <span className="text-[#4f7cff] text-sm uppercase tracking-[0.3em]">
            About Me
          </span>

          <h2 className="mt-6 text-[clamp(3rem,7vw,5rem)] font-bold text-white leading-tight">
            Passionate about building
            <br />
            intelligent systems.
          </h2>
        </motion.div>

        {/* Main Layout */}
        <div className="grid lg:grid-cols-2 gap-20 items-start">
          {/* Left Side */}
          <motion.div
            initial={{ opacity: 0, x: -40 }}
            whileInView={{ opacity: 1, x: 0 }}
            viewport={{ once: true }}
          >
            <p className="text-slate-300 text-xl leading-relaxed mb-8">
              I'm <span className="text-white font-semibold">Hana Al Haris</span>,
              an AI/ML Engineer based in Bangalore, India, focused on building
              scalable machine learning systems, agentic AI applications,
              and financial intelligence platforms.
            </p>

            <p className="text-slate-500 leading-relaxed mb-8">
              My work combines machine learning, large language models,
              graph-based intelligence, and production engineering to create
              systems that reason, investigate, and automate complex workflows.
            </p>

            <p className="text-slate-500 leading-relaxed">
              Currently pursuing B.Tech in Computer Science (AI & ML)
              at JAIN University while building enterprise-grade AI solutions
              and preparing for full-time AI/ML engineering opportunities.
            </p>
          </motion.div>

          {/* Right Side */}
          <div className="space-y-8">
            {highlights.map((item, index) => (
              <motion.div
                key={item.number}
                initial={{ opacity: 0, y: 30 }}
                whileInView={{ opacity: 1, y: 0 }}
                viewport={{ once: true }}
                transition={{
                  delay: index * 0.15,
                }}
                className="border-b border-white/10 pb-8"
              >
                <div className="text-[#4f7cff] text-sm font-medium mb-3">
                  {item.number}
                </div>

                <h3 className="text-white text-2xl font-bold mb-3">
                  {item.title}
                </h3>

                <p className="text-slate-500 leading-relaxed">
                  {item.description}
                </p>
              </motion.div>
            ))}
          </div>
        </div>

        {/* Quick Stats */}
        <motion.div
          initial={{ opacity: 0 }}
          whileInView={{ opacity: 1 }}
          viewport={{ once: true }}
          className="grid md:grid-cols-4 gap-6 mt-28"
        >
          <div className="border border-white/10 rounded-3xl p-6 bg-white/[0.02]">
            <h3 className="text-4xl font-bold text-[#4f7cff]">4+</h3>
            <p className="text-slate-500 mt-2">AI Projects</p>
          </div>

          <div className="border border-white/10 rounded-3xl p-6 bg-white/[0.02]">
            <h3 className="text-4xl font-bold text-[#4f7cff]">15+</h3>
            <p className="text-slate-500 mt-2">Technologies</p>
          </div>

          <div className="border border-white/10 rounded-3xl p-6 bg-white/[0.02]">
            <h3 className="text-4xl font-bold text-[#4f7cff]">2</h3>
            <p className="text-slate-500 mt-2">Internships</p>
          </div>

          <div className="border border-white/10 rounded-3xl p-6 bg-white/[0.02]">
            <h3 className="text-4xl font-bold text-[#4f7cff]">7.8</h3>
            <p className="text-slate-500 mt-2">CGPA</p>
          </div>
        </motion.div>
      </div>
    </section>
  );
}
